import redis, json, time, uuid
from dataclasses import dataclass, asdict
from enum import Enum

r = redis.Redis(host="localhost", port=6379, decode_responses=True)

class Priority(str, Enum):
    CRITICAL = "critical"
    HIGH     = "high"
    NORMAL   = "normal"
    BATCH    = "batch"

QUEUE_KEY = {p: f"pq:{p.value}" for p in Priority}

@dataclass
class AgentJob:
    job_id:    str
    priority:  str
    tenant_id: str
    messages:  list[dict]
    tools:     list[dict]
    model:     str = "claude-opus-4-8"
    max_tokens: int = 4096
    enqueued_at: float = 0.0

    @classmethod
    def new(cls, priority: Priority, tenant_id: str,
            messages: list, tools: list) -> "AgentJob":
        return cls(
            job_id=str(uuid.uuid4()),
            priority=priority.value,
            tenant_id=tenant_id,
            messages=messages,
            tools=tools,
        )


def enqueue(job: AgentJob, priority: Priority) -> None:
    job.enqueued_at = time.time()
    score = job.enqueued_at  # lower = older = higher urgency within tier
    r.zadd(QUEUE_KEY[priority], {json.dumps(asdict(job)): score})


def queue_depth(priority: Priority) -> int:
    return r.zcard(QUEUE_KEY[priority])

POLL_ORDER = [Priority.CRITICAL, Priority.HIGH, Priority.NORMAL, Priority.BATCH]

def next_job(block_timeout: float = 1.0) -> AgentJob | None:
    """
    Pop from the highest-priority non-empty queue.
    Returns None if all queues are empty after block_timeout seconds.
    """
    # Non-blocking pass: drain higher tiers first
    for priority in POLL_ORDER[:-1]:
        item = r.bzpopmin(QUEUE_KEY[priority], timeout=0)
        if item:
            _, payload, _ = item
            return AgentJob(**json.loads(payload))

    # Blocking pass: wait on all queues simultaneously
    # BZPOPMIN accepts multiple keys; returns the first that fires
    keys = [QUEUE_KEY[p] for p in POLL_ORDER]
    result = r.bzpopmin(keys, timeout=block_timeout)
    if result:
        _, payload, _ = result
        return AgentJob(**json.loads(payload))
    return None


def worker_loop():
    import anthropic
    client = anthropic.Anthropic()

    while True:
        job = next_job(block_timeout=2.0)
        if job is None:
            continue

        wait_ms = int((time.time() - job.enqueued_at) * 1000)
        print(f"[{job.priority}] job={job.job_id} waited={wait_ms}ms")

        try:
            response = client.messages.create(
                model=job.model,
                max_tokens=job.max_tokens,
                messages=job.messages,
                tools=job.tools,
            )
            store_result(job.job_id, response.content[0].text)
        except Exception as exc:
            handle_failure(job, exc)

import threading

WORKER_ALLOCATION = {
    Priority.CRITICAL: 4,   # 4 dedicated workers
    Priority.HIGH:     3,
    Priority.NORMAL:   2,
    Priority.BATCH:    1,   # 1 batch worker always running
}

def start_worker_pool():
    threads = []
    for priority, count in WORKER_ALLOCATION.items():
        for _ in range(count):
            def make_worker(p=priority):
                # This worker only pulls from its tier and above
                tiers = [t for t in POLL_ORDER
                         if POLL_ORDER.index(t) <= POLL_ORDER.index(p)]
                while True:
                    for tier in tiers:
                        item = r.bzpopmin(QUEUE_KEY[tier], timeout=0)
                        if item:
                            _, payload, _ = item
                            process(AgentJob(**json.loads(payload)))
                            break
                    else:
                        time.sleep(0.1)
            t = threading.Thread(target=make_worker, daemon=True)
            t.start()
            threads.append(t)
    return threads

def queue_health_report() -> dict:
    """Snapshot of queue depth and oldest job wait per tier."""
    report = {}
    now = time.time()
    for priority in Priority:
        key   = QUEUE_KEY[priority]
        depth = r.zcard(key)
        oldest_score = None
        if depth > 0:
            # zrange with withscores=True, limit 1
            items = r.zrange(key, 0, 0, withscores=True)
            if items:
                oldest_score = items[0][1]
        wait_s = (now - oldest_score) if oldest_score else 0
        report[priority.value] = {
            "depth":   depth,
            "wait_s":  round(wait_s, 1),
        }
    return report

