import itertools

class FairTierWorker:
    """
    Within a single tier, drain jobs round-robin across tenants
    so no single tenant monopolises the workers.
    """
    def __init__(self, priority: Priority):
        self.priority       = priority
        self.tenant_cycle   = None  # populated lazily
        self.last_seen_tenants: set[str] = set()

    def _tenant_sub_key(self, tenant_id: str) -> str:
        return f"pq:{self.priority.value}:tenant:{tenant_id}"

    def enqueue(self, job: AgentJob) -> None:
        score = time.time()
        r.zadd(self._tenant_sub_key(job.tenant_id),
               {json.dumps(job.__dict__): score})
        # Also track which tenants are active
        r.sadd(f"pq:{self.priority.value}:tenants", job.tenant_id)

    def next_job(self) -> AgentJob | None:
        tenants = list(r.smembers(f"pq:{self.priority.value}:tenants"))
        if not tenants:
            return None
        # Cycle through tenants
        for tenant_id in tenants:
            key  = self._tenant_sub_key(tenant_id)
            item = r.bzpopmin(key, timeout=0)
            if item:
                _, payload, _ = item
                # Clean up empty tenant
                if r.zcard(key) == 0:
                    r.srem(f"pq:{self.priority.value}:tenants", tenant_id)
                return AgentJob(**json.loads(payload))
        return None
